package co.istad.makara.common.application.exception;import co.istad.makara.common.domain.exception.DomainException;import lombok.Getter;@Getterpublic class ApplicationException extends RuntimeException {    private final int code;    public ApplicationException(String message, int code) {        super(message);        this.code = code;    }    public ApplicationException(String message, int code, Throwable cause) {        super(message, cause);        this.code = code;    }    public static ApplicationException fromDomain(DomainException domainException, int code) {        return new ApplicationException(domainException.getMessage(), code, domainException);    }}